var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"기상! 기상하십시오! 기상!","JPN":"起床！起床してください！起床！","ENG":"Wake up! Rise and shine! Wake up!","TWN":"起床！起床了！起床！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"으음...... 바보 주르...... 날 깨우지 마.","JPN":"う～ん……J.O.U.Rのバカ……私を起こさないで。","ENG":"Hngh... Stupid J.O.U.R.... Don't wake me up.","TWN":"唔唔……笨蛋朱爾……別叫我啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"알람 시작 10분 경과! 탑승자가 깨어나지 않으므로 응급조치 시퀀스를 기동합니다!","JPN":"アラーム開始から10分経過！搭乗者が起きないため、応急処置シークエンスを起動します！","ENG":"10 minutes have elapsed since the alarm has gone off! Commencing emergency sequence as the passenger has failed to rise from slumber!","TWN":"鬧鐘時間超過10分鐘！由於搭乘者仍未醒來，啟動應急措施程序！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"10... 9... 8...","JPN":"10……9……8……","ENG":"10... 9... 8...","TWN":"10…9…8…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"5... 4... 3... 2...","JPN":"5……4……3……2……","ENG":"5... 4... 3... 2...","TWN":"5…4…3…2…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"1......","JPN":"1……","ENG":"1......","TWN":"1……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"알람을 정지합니다. 좋은 하루 되세요.","JPN":"アラームを停止します。良い一日を。","ENG":"Disabling alarm. Have a nice day.","TWN":"關閉鬧鐘，祝您度過美好的一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"흐으음...... 팬더야 날아라, 날아...... 헤헤......","JPN":"ふ～ん……パンダちゃん、飛べ、飛べ……へへ……","ENG":"Hmm... Fly panda, fly... Heh...","TWN":"哈啊啊……熊貓，飛吧，飛吧……嘿嘿……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"......응?","JPN":"……あれ？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"아하하~ 사장~ 왜 그런 우스꽝스런 자세로 땀을 흘리고 있어?","JPN":"あはは～社長～何でおかしいポーズで汗かいてるの？","ENG":"Hah hah! Boss! Why are you sweating in such an awkward position?","TWN":"啊哈哈～老闆～你怎麼擺出一個滑稽的姿勢，還流那麼多汗？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"응? 의자가 자폭 카운트 하는 걸 직접 멈췄다고?","JPN":"うん？椅子が自爆カウントしていたから直接止めた？","ENG":"Huh? You stopped the chair from counting down to the self-destruct sequence?","TWN":"嗯？你親自關閉了椅子的自爆倒數計時？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"아아~ 괜찮아~ 주르가 말하는 응급조치는 진동마사지로 내 피로를 풀어주는 거거든~","JPN":"ああ～大丈夫だよ～。J.O.U.Rが言ってる応急処置は、振動マッサージで私の疲労をほぐしてくれるってことだから～。","ENG":"Oh, that's okay. What J.O.U.R. meant by the emergency protocol is a massage. It helps me relax.","TWN":"啊啊～沒事啦～朱爾說的應急措施就是震動按摩啦，幫我消除疲勞用的～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"그래도 감동이네~ 날 깨우지 않고 직접 멈춰주다니~ 역시 사장은 좋은 사람이구나?","JPN":"でも感動したよ～。私を起こさないで止めてくれたなんて～やっぱり社長はいい人なんだね。","ENG":"But I'm so touched! You shut it down without waking me up! You're a nice person, as I thought.","TWN":"不過我好感動啊～你居然沒叫醒我，直接關了鬧鐘～老闆你果然是個好人啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"음...... 그러고 보니 나 왜 여기 있는 거야......?","JPN":"あれ……そう言えば私、何でここにいるの……？","ENG":"Um... Come to think of it, what am I doing here?","TWN":"嗯……可是我怎麼會在這裡啊……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"진지한 얘기? 종신계약? ......우리가 그런 걸 했었나?","JPN":"大事な話？終身契約？……そんなこと話してたっけ？","ENG":"You want to have a serious conversation? A lifetime contract? Since when were we in that sort of a relationship?","TWN":"重要的事？終身雇傭？……我們有做過這個嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"으응...... 이걸로 벌써 세 번째라고?","JPN":"ううん……これでもう3回目だって？","ENG":"Erm... This is the third time already?","TWN":"呃嗯……你說這已經是第三次了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"알았어~ 그렇게 할게...... 이미 제멋대로 날 자기네들 소속 연구원이라고 추켜세우면서 부려먹는 어른들도 있는걸~","JPN":"わかった～そうするよ……もうすでに私のことを、自分たちのチームの研究員だってこき使う大人たちもいるんだもん～。","ENG":"Okay, then. I'll do it... I've already got grown-ups claiming that I'm a part of their research center without my permission.","TWN":"我知道了～那就這樣吧……有一些大人已經擅自把我當成他們的所屬研究員到處炫耀，對我頤指氣使的呢～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"난...... 고철값 내주고 수면시간만 보장해준다면...... 어디서 일하든 상관없어......","JPN":"私……材料代を出してもらったり、睡眠時間さえ確保できれば……仕事先なんか気にしないから……","ENG":"So... As long as you pay for my scrap metal and guarantee my sleep hours... I really couldn't care less whom I work for...","TWN":"我啊……只要給我買廢金屬，再保障我的睡眠時間……在哪工作都無所謂……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"물론 그 사람이 나쁜 악당이라면 절~대 안 도와주겠지만...... 사장님은 좋은 사람이니까......","JPN":"もちろんその人が悪い人なら、絶対に～手伝わないけど……社長はいい人だから……","ENG":"Of course, I'd never help a bad guy. But you seem like a good one...","TWN":"當然如果那個人是壞蛋，我是絕～對不會幫忙的……但老闆你是好人嘛……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"뭐어...... 분위기가 악당인 것까진 괜찮아...... 나도 이런 어두컴컴한 공간 좋아하거든......","JPN":"まぁ……悪党っぽい感じは大丈夫だよ……私もこの暗い空間が好きだから……","ENG":"Well... Sometimes you do give off that bad guy vibe, but that's alright... I also like dark places like this...","TWN":"好吧……壞人的氛圍我可以接受……因為我也喜歡這種昏暗的空間……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"이렇게 어두운 곳에 있으면 잠도 저절로 솔솔......","JPN":"こんなに暗い場所にいると、眠くなるね……","ENG":"It really helps me go to sleep...","TWN":"在這種昏暗的地方待著，自然而然就會睡著……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"하암......","JPN":"ふああ……","ENG":"*Yawn*","TWN":"哈啊……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"사장도 피곤해 보이는데 눈 좀 붙여...... 잠을 아껴가면서 살기엔 인생이 너무 짧지 않아?","JPN":"社長も疲れてるよね。少し寝てよ……睡眠時間を減らしてまで生きるには、人生は短すぎると思わない？","ENG":"You seem tired too... Why don't you take a nap? Isn't life to short to miss out on napping?","TWN":"老闆看起來也很累的樣子，稍微眯一下眼睛吧……你說太喜歡睡覺的話，人生就會太短嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"성공한 위인들이 잠을 적게 잔 덕을 봤을진 몰라도...... 대부분의 행복한 사람들은 잠을 실컷 자면서 살았을 거라구~","JPN":"成功した偉人たちは睡眠時間を減らしたことでメリットを得たかもしれないけど……幸せな人のほとんどは、十分な睡眠をとっているはずだよ～。","ENG":"Sure, the greatest achievers may have slept a little less... But I'm sure the happiest folks got plenty of sleep...","TWN":"也許成功的偉人是因為睡得少才有成就的……但幸福的人幾乎都是想睡就睡喔～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"하~~~ 품~","JPN":"ふああ～～～。","ENG":"*Yawwwn*","TWN":"哈～～～噗～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"으음......","JPN":"う～ん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"아...... 맞다......","JPN":"あ……そうだ……","ENG":"Oh... That's right...","TWN":"啊……對了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_RA","text":{"KOREA":"내 손은 여기 올려둘게...... 계약서...... 알아서 잘 찍어줘.","JPN":"私の手はここに置いておくね……契約書は任せた。","ENG":"I'll leave my hand up here... If you need my signature... Feel free to take my hand...","TWN":"我的手放在這裡……契約書……你就自己蓋手印吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_RA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};